/**
 * Email notification adapter — delivers notifications via email.
 *
 * Features:
 * - Template rendering: maps NotificationType to HTML/text email templates
 * - Recipient resolution: validates email addresses before sending
 * - Configurable sender and retry behavior
 * - In-memory transport for testing (swap with real SMTP/API provider)
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/** Configuration for the email adapter. */
export interface EmailConfig {
  /** Sender email address shown in the "From" field */
  from: string;
  /** Application name used in templates */
  appName: string;
  /** Maximum retries on transient failure */
  maxRetries: number;
}

/** A rendered email ready for delivery. */
export interface EmailMessage {
  to: string;
  from: string;
  subject: string;
  bodyText: string;
  bodyHtml: string;
  sentAt: Date;
  notificationId: string;
  notificationType: NotificationType;
}

/** Result of a template render step. */
export interface RenderedTemplate {
  subject: string;
  bodyText: string;
  bodyHtml: string;
}

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

const DEFAULT_CONFIG: EmailConfig = {
  from: 'noreply@taskflowpro.com',
  appName: 'TaskFlow Pro',
  maxRetries: 2,
};

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: EmailMessage[] = [];
  private config: EmailConfig;
  /** Pluggable transport — override for testing or real providers. */
  private transport: (email: EmailMessage) => Promise<void>;

  constructor(config?: Partial<EmailConfig>) {
    this.config = { ...DEFAULT_CONFIG, ...config };
    // Default transport: in-memory store (replace with SMTP/SendGrid/SES)
    this.transport = async (email: EmailMessage) => {
      this.sentEmails.push(email);
    };
  }

  /**
   * Replace the default in-memory transport with a custom one.
   * Use this to plug in a real email provider (SendGrid, SES, SMTP, etc.).
   */
  setTransport(transport: (email: EmailMessage) => Promise<void>): void {
    this.transport = transport;
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const validationError = this.validateRecipient(payload.recipient);
    if (validationError) {
      this.logger.warn(`Invalid recipient "${payload.recipient}": ${validationError}`);
      return {
        success: false,
        notificationId: payload.id,
        channel: this.channel,
        deliveredAt: new Date(),
        error: validationError,
      };
    }

    const rendered = this.renderTemplate(payload);

    const email: EmailMessage = {
      to: payload.recipient,
      from: this.config.from,
      subject: rendered.subject,
      bodyText: rendered.bodyText,
      bodyHtml: rendered.bodyHtml,
      sentAt: new Date(),
      notificationId: payload.id,
      notificationType: payload.type,
    };

    let lastError: string | undefined;
    for (let attempt = 0; attempt <= this.config.maxRetries; attempt++) {
      try {
        await this.transport(email);
        this.logger.info(
          `Email sent to ${email.to}: "${email.subject}" (attempt ${attempt + 1})`,
        );
        return {
          success: true,
          notificationId: payload.id,
          channel: this.channel,
          deliveredAt: email.sentAt,
        };
      } catch (err) {
        lastError = err instanceof Error ? err.message : String(err);
        this.logger.warn(
          `Email send attempt ${attempt + 1} failed for ${email.to}: ${lastError}`,
        );
      }
    }

    this.logger.error(
      `Email delivery failed after ${this.config.maxRetries + 1} attempts for ${email.to}`,
    );
    return {
      success: false,
      notificationId: payload.id,
      channel: this.channel,
      deliveredAt: new Date(),
      error: `Delivery failed after ${this.config.maxRetries + 1} attempts: ${lastError}`,
    };
  }

  /**
   * Validate that the recipient is a well-formed email address.
   * Returns an error message if invalid, or undefined if valid.
   */
  validateRecipient(recipient: string): string | undefined {
    if (!recipient || recipient.trim().length === 0) {
      return 'Recipient email is empty';
    }
    if (!EMAIL_REGEX.test(recipient)) {
      return `Invalid email format: ${recipient}`;
    }
    return undefined;
  }

  /**
   * Render an email template based on the notification type.
   * Returns subject, plain-text body, and HTML body.
   */
  renderTemplate(payload: NotificationPayload): RenderedTemplate {
    switch (payload.type) {
      case 'order-confirmation':
        return this.renderOrderConfirmation(payload);
      case 'order-status-update':
        return this.renderOrderStatusUpdate(payload);
      case 'welcome':
        return this.renderWelcome(payload);
      case 'user-updated':
        return this.renderUserUpdated(payload);
      default:
        return this.renderGeneric(payload);
    }
  }

  private renderOrderConfirmation(payload: NotificationPayload): RenderedTemplate {
    const items = (payload.metadata?.['items'] as string) ?? '';
    const total = (payload.metadata?.['total'] as string) ?? '';

    return {
      subject: payload.subject,
      bodyText: payload.body,
      bodyHtml: [
        `<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">`,
        `  <h1 style="color: #2563eb;">Order Confirmed</h1>`,
        `  <p>Thank you for your order!</p>`,
        `  <div style="background: #f3f4f6; padding: 16px; border-radius: 8px;">`,
        `    <p>${this.escapeHtml(payload.body)}</p>`,
        items ? `    <p><strong>Items:</strong> ${this.escapeHtml(items)}</p>` : '',
        total ? `    <p><strong>Total:</strong> ${this.escapeHtml(total)}</p>` : '',
        `  </div>`,
        `  <p style="color: #6b7280; font-size: 12px;">— ${this.config.appName}</p>`,
        `</div>`,
      ]
        .filter(Boolean)
        .join('\n'),
    };
  }

  private renderOrderStatusUpdate(payload: NotificationPayload): RenderedTemplate {
    const previousStatus = (payload.metadata?.['previousStatus'] as string) ?? '';
    const newStatus = (payload.metadata?.['newStatus'] as string) ?? '';

    return {
      subject: payload.subject,
      bodyText: payload.body,
      bodyHtml: [
        `<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">`,
        `  <h1 style="color: #2563eb;">Order Status Update</h1>`,
        `  <p>${this.escapeHtml(payload.body)}</p>`,
        previousStatus && newStatus
          ? `  <p><span style="color: #6b7280;">${this.escapeHtml(previousStatus)}</span> → <strong>${this.escapeHtml(newStatus)}</strong></p>`
          : '',
        `  <p style="color: #6b7280; font-size: 12px;">— ${this.config.appName}</p>`,
        `</div>`,
      ]
        .filter(Boolean)
        .join('\n'),
    };
  }

  private renderWelcome(payload: NotificationPayload): RenderedTemplate {
    return {
      subject: payload.subject,
      bodyText: payload.body,
      bodyHtml: [
        `<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">`,
        `  <h1 style="color: #2563eb;">Welcome to ${this.escapeHtml(this.config.appName)}!</h1>`,
        `  <p>${this.escapeHtml(payload.body)}</p>`,
        `  <p>We're glad to have you on board.</p>`,
        `  <p style="color: #6b7280; font-size: 12px;">— The ${this.config.appName} Team</p>`,
        `</div>`,
      ].join('\n'),
    };
  }

  private renderUserUpdated(payload: NotificationPayload): RenderedTemplate {
    return {
      subject: payload.subject,
      bodyText: payload.body,
      bodyHtml: [
        `<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">`,
        `  <h1 style="color: #2563eb;">Account Updated</h1>`,
        `  <p>${this.escapeHtml(payload.body)}</p>`,
        `  <p style="color: #6b7280; font-size: 12px;">— ${this.config.appName}</p>`,
        `</div>`,
      ].join('\n'),
    };
  }

  private renderGeneric(payload: NotificationPayload): RenderedTemplate {
    return {
      subject: payload.subject,
      bodyText: payload.body,
      bodyHtml: [
        `<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">`,
        `  <h1 style="color: #2563eb;">${this.escapeHtml(payload.subject)}</h1>`,
        `  <p>${this.escapeHtml(payload.body)}</p>`,
        `  <p style="color: #6b7280; font-size: 12px;">— ${this.config.appName}</p>`,
        `</div>`,
      ].join('\n'),
    };
  }

  /** Escape HTML special characters to prevent XSS in email templates. */
  private escapeHtml(text: string): string {
    return text
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  /** Get all sent emails (for testing). */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /** Clear sent emails (for testing). */
  clearSentEmails(): void {
    this.sentEmails = [];
  }

  /** Get the current configuration. */
  getConfig(): EmailConfig {
    return { ...this.config };
  }
}

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order-confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    createdAt: new Date('2026-01-01'),
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;

  beforeEach(() => {
    adapter = new EmailAdapter();
  });

  describe('constructor and config', () => {
    it('should use default config', () => {
      const config = adapter.getConfig();
      expect(config.from).toBe('noreply@taskflowpro.com');
      expect(config.appName).toBe('TaskFlow Pro');
      expect(config.maxRetries).toBe(2);
    });

    it('should accept custom config', () => {
      const custom = new EmailAdapter({
        from: 'hello@example.com',
        appName: 'My App',
        maxRetries: 0,
      });
      const config = custom.getConfig();
      expect(config.from).toBe('hello@example.com');
      expect(config.appName).toBe('My App');
      expect(config.maxRetries).toBe(0);
    });

    it('should report email channel', () => {
      expect(adapter.channel).toBe('email');
    });
  });

  describe('recipient validation', () => {
    it('should accept valid email addresses', () => {
      expect(adapter.validateRecipient('user@example.com')).toBeUndefined();
      expect(adapter.validateRecipient('a.b+tag@domain.co.uk')).toBeUndefined();
    });

    it('should reject empty recipient', () => {
      expect(adapter.validateRecipient('')).toBe('Recipient email is empty');
      expect(adapter.validateRecipient('   ')).toBe('Recipient email is empty');
    });

    it('should reject invalid email format', () => {
      expect(adapter.validateRecipient('not-an-email')).toContain('Invalid email format');
      expect(adapter.validateRecipient('@missing-local.com')).toContain('Invalid email format');
      expect(adapter.validateRecipient('missing@')).toContain('Invalid email format');
    });

    it('should return failure result for invalid recipient on send', async () => {
      const payload = makePayload({ recipient: 'bad-email' });
      const result = await adapter.send(payload);
      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email format');
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });

  describe('template rendering', () => {
    it('should render order-confirmation template with HTML', () => {
      const payload = makePayload({ type: 'order-confirmation' });
      const rendered = adapter.renderTemplate(payload);
      expect(rendered.subject).toBe(payload.subject);
      expect(rendered.bodyText).toBe(payload.body);
      expect(rendered.bodyHtml).toContain('Order Confirmed');
      expect(rendered.bodyHtml).toContain(payload.body);
    });

    it('should render order-status-update template', () => {
      const payload = makePayload({
        type: 'order-status-update',
        subject: 'Order Update: order-1',
        body: 'Your order status has changed from pending to confirmed.',
        metadata: { previousStatus: 'pending', newStatus: 'confirmed' },
      });
      const rendered = adapter.renderTemplate(payload);
      expect(rendered.bodyHtml).toContain('Order Status Update');
      expect(rendered.bodyHtml).toContain('pending');
      expect(rendered.bodyHtml).toContain('confirmed');
    });

    it('should render welcome template', () => {
      const payload = makePayload({
        type: 'welcome',
        subject: 'Welcome to TaskFlow Pro',
        body: 'Hi Alice, welcome to TaskFlow Pro!',
      });
      const rendered = adapter.renderTemplate(payload);
      expect(rendered.bodyHtml).toContain('Welcome to TaskFlow Pro');
      expect(rendered.bodyHtml).toContain('glad to have you');
    });

    it('should render user-updated template', () => {
      const payload = makePayload({
        type: 'user-updated',
        subject: 'Account Updated',
        body: 'Your account details have been updated.',
      });
      const rendered = adapter.renderTemplate(payload);
      expect(rendered.bodyHtml).toContain('Account Updated');
    });

    it('should escape HTML in template content', () => {
      const payload = makePayload({
        body: '<script>alert("xss")</script>',
      });
      const rendered = adapter.renderTemplate(payload);
      expect(rendered.bodyHtml).not.toContain('<script>');
      expect(rendered.bodyHtml).toContain('&lt;script&gt;');
    });
  });

  describe('send', () => {
    it('should send email and record it', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('email');
      expect(result.deliveredAt).toBeInstanceOf(Date);

      const sent = adapter.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]!.to).toBe('alice@example.com');
      expect(sent[0]!.from).toBe('noreply@taskflowpro.com');
      expect(sent[0]!.bodyHtml).toContain('Order Confirmed');
      expect(sent[0]!.notificationType).toBe('order-confirmation');
    });

    it('should set from address from config', async () => {
      const custom = new EmailAdapter({ from: 'team@acme.co' });
      await custom.send(makePayload());
      expect(custom.getSentEmails()[0]!.from).toBe('team@acme.co');
    });

    it('should clear sent emails', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentEmails()).toHaveLength(1);
      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });

  describe('retry behavior', () => {
    it('should retry on transport failure and succeed', async () => {
      let attempts = 0;
      adapter.setTransport(async () => {
        attempts++;
        if (attempts < 2) throw new Error('Transient failure');
      });

      const result = await adapter.send(makePayload());
      expect(result.success).toBe(true);
      expect(attempts).toBe(2);
    });

    it('should fail after exhausting retries', async () => {
      adapter.setTransport(async () => {
        throw new Error('Permanent failure');
      });

      const result = await adapter.send(makePayload());
      expect(result.success).toBe(false);
      expect(result.error).toContain('Delivery failed after 3 attempts');
      expect(result.error).toContain('Permanent failure');
    });

    it('should respect maxRetries config', async () => {
      const noRetry = new EmailAdapter({ maxRetries: 0 });
      let attempts = 0;
      noRetry.setTransport(async () => {
        attempts++;
        throw new Error('fail');
      });

      const result = await noRetry.send(makePayload());
      expect(result.success).toBe(false);
      expect(attempts).toBe(1);
      expect(result.error).toContain('Delivery failed after 1 attempts');
    });
  });

  describe('custom transport', () => {
    it('should use custom transport when set', async () => {
      const captured: Array<{ to: string; subject: string }> = [];
      adapter.setTransport(async (email) => {
        captured.push({ to: email.to, subject: email.subject });
      });

      await adapter.send(makePayload());
      expect(captured).toHaveLength(1);
      expect(captured[0]!.to).toBe('alice@example.com');
      // Default in-memory store should NOT have the email since we replaced transport
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });
});
